const request = $.input.contentRequest || '';

let prompt = 'You are a social media content strategist. Extract the content intent from this request.\n\n';
prompt += 'REQUEST: ' + request + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "platform": "twitter|linkedin|instagram|facebook|general",\n';
prompt += '  "contentType": "post|thread|story|carousel|reel_caption",\n';
prompt += '  "topic": "main topic",\n';
prompt += '  "targetAudience": "who this is for",\n';
prompt += '  "tone": "desired tone",\n';
prompt += '  "goal": "engagement|education|promotion|awareness",\n';
prompt += '  "constraints": { "maxLength": 0, "hashtagCount": 0, "emojiLevel": "none|minimal|moderate|heavy" }\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiIntent.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { platform: 'general', contentType: 'post', topic: $.input.contentRequest, targetAudience: 'general', tone: 'professional', goal: 'engagement', constraints: {} }; }

const intent = $.steps.parseIntent.output;

let prompt = 'You are a content strategist and copywriter. Given the content intent below, create a content strategy with emotional framing, outline, and the final polished content.

';
prompt += 'INTENT:
';
prompt += '- Platform: ' + intent.platform + '
';
prompt += '- Type: ' + intent.contentType + '
';
prompt += '- Topic: ' + intent.topic + '
';
prompt += '- Audience: ' + intent.targetAudience + '
';
prompt += '- Tone: ' + intent.tone + '
';
prompt += '- Goal: ' + intent.goal + '

';
prompt += 'ORIGINAL REQUEST: ' + $.input.contentRequest + '

';
prompt += 'Create the content through these stages:
';
prompt += '1. Strategy: key messaging angles and hooks
';
prompt += '2. Emotional Framing: what emotions to evoke
';
prompt += '3. Outline: structure of the content
';
prompt += '4. Final Content: polished, ready-to-publish

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "strategy": { "keyAngles": [""], "hooks": [""], "cta": "" },
';
prompt += '  "emotionalFraming": { "primaryEmotion": "", "secondaryEmotion": "", "framework": "" },
';
prompt += '  "outline": [""],
';
prompt += '  "content": { "text": "the final post text", "hashtags": [""], "altVersions": ["shorter version"] },
';
prompt += '  "metrics": { "estimatedEngagement": "high|medium|low", "bestTime": "", "tips": [""] }
';
prompt += '}';
return { prompt };

let raw = $.steps.aiStrategy.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { strategy: { keyAngles: [], hooks: [], cta: '' }, emotionalFraming: { primaryEmotion: '', secondaryEmotion: '', framework: '' }, outline: [], content: { text: raw, hashtags: [], altVersions: [] }, metrics: {} }; }

const s = $.steps.parseStrategy.output;
const intent = $.steps.parseIntent.output;

let body = 'SOCIAL MEDIA CONTENT STRATEGY\n';
body += '============================\n\n';
body += 'Platform: ' + intent.platform + ' | Type: ' + intent.contentType + '\n';
body += 'Topic: ' + intent.topic + '\n\n';
body += 'STRATEGY\n';
if (s.strategy && s.strategy.hooks) {
  body += 'Hooks: ' + s.strategy.hooks.join(', ') + '\n';
}
if (s.strategy && s.strategy.cta) body += 'CTA: ' + s.strategy.cta + '\n\n';
body += 'EMOTIONAL FRAMING\n';
if (s.emotionalFraming) {
  body += 'Primary: ' + s.emotionalFraming.primaryEmotion + '\n';
  body += 'Framework: ' + (s.emotionalFraming.framework || '') + '\n\n';
}
body += 'FINAL CONTENT\n';
body += '-------------\n';
body += (s.content?.text || '') + '\n\n';
if (s.content?.hashtags) body += 'Hashtags: ' + s.content.hashtags.join(' ') + '\n\n';
if (s.content?.altVersions && s.content.altVersions.length > 0) {
  body += 'ALT VERSION:\n' + s.content.altVersions[0] + '\n';
}
return { body: body, subject: 'Social Content: ' + intent.topic };

const s = $.steps.parseStrategy.output;
const intent = $.steps.parseIntent.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Social Media Content Generated', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Platform:*\n' + (intent.platform || 'N/A') },
  { type: 'mrkdwn', text: '*Type:*\n' + (intent.contentType || 'N/A') }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (s.content?.text || '').slice(0, 1800) } });
if (s.content?.hashtags && s.content.hashtags.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: s.content.hashtags.join(' ') } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Sent to ' + $.input.recipientEmail + ' | Multi-stage AI pipeline' }] });
const fallbackText = 'Social content ready for ' + (intent.platform || 'posting') + ': ' + (intent.topic || $.input.contentRequest).slice(0, 80);
return { blocks, fallbackText };
